Below test, rewritten from UVM tests/20sequences/10sequence_lib/3567_default_type, gives an internal error after V3LinkDot arrayed stage:

``` 
  %Error: Internal Error: t/t_0.v:37:3: ../V3Broken.cpp:182: Broken link in node (or something without maybePointedTo): 'm_varp && !m_varp->brokeExists()' @ ./V3Ast__g$
     37 |   class t1 extends uvm_sequence_library;
        |   ^~~~~
```

```
package uvm_pkg;

  virtual class uvm_sequence #(
      type REQ = int
  );
  endclass

  class uvm_sequence_library #(
      type REQ = int
  ) extends uvm_sequence #(REQ);
    randc bit [15:0] select_randc;  // Passes without randc here
    task body();
      if (0 == randomize(select_randc)) begin
      end
    endtask
  endclass
endpackage

module t;
  import uvm_pkg::*;

  class t1 extends uvm_sequence_library;
  endclass

  initial begin
    t1 c;
    c = new;
    c.body;
    $finish;
  end

endmodule
```
